import { useEffect, useMemo, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { Globe, XCircle } from "lucide-react";
import { useTranslation } from "@/i18n";
import { storageKey } from "@/utils/storage";

const ALL_REGIONS = [
  "Afghanistan",
  "Albania",
  "Algeria",
  "Argentina",
  "Australia",
  "Austria",
  "Bangladesh",
  "Belgium",
  "Brazil",
  "Canada",
  "Chile",
  "China",
  "Colombia",
  "Czech Republic",
  "Denmark",
  "Egypt",
  "Finland",
  "France",
  "Germany",
  "Greece",
  "Hong Kong",
  "India",
  "Indonesia",
  "Ireland",
  "Israel",
  "Italy",
  "Japan",
  "Malaysia",
  "Mexico",
  "Netherlands",
  "New Zealand",
  "Nigeria",
  "Norway",
  "Pakistan",
  "Philippines",
  "Poland",
  "Portugal",
  "Russia",
  "Saudi Arabia",
  "Singapore",
  "South Africa",
  "South Korea",
  "Spain",
  "Sweden",
  "Switzerland",
  "Taiwan",
  "Thailand",
  "Turkey",
  "Ukraine",
  "United Arab Emirates",
  "United Kingdom",
  "United States",
  "Vietnam",
];

export default function ServiceRestrictionsPage() {
  const { t } = useTranslation();
  const [restrictedRegions, setRestrictedRegions] = useState<string>("");
  const [regionSearchQuery, setRegionSearchQuery] = useState<string>("");
  const [filteredRegions, setFilteredRegions] = useState<string[]>([]);
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    setRestrictedRegions(
      localStorage.getItem(storageKey("orderlyRestrictedRegions")) || ""
    );
  }, []);

  const selectedRegions = useMemo(() => {
    if (!restrictedRegions) return [];
    return restrictedRegions
      .split(",")
      .map(r => r.trim())
      .filter(Boolean);
  }, [restrictedRegions]);

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  function handleRegionSearch(query: string) {
    setRegionSearchQuery(query);
    if (!query.trim()) {
      setFilteredRegions([]);
      return;
    }

    const queryLower = query.toLowerCase();
    const filtered = ALL_REGIONS.filter(region =>
      region.toLowerCase().includes(queryLower)
    ).slice(0, 10);
    setFilteredRegions(filtered);
  }

  function handleSelectRegion(region: string) {
    if (selectedRegions.includes(region)) return;

    const newRegions = [...selectedRegions, region];
    const newValue = newRegions.join(",");
    setRestrictedRegions(newValue);
    localStorage.setItem(storageKey("orderlyRestrictedRegions"), newValue);
    setRegionSearchQuery("");
    setFilteredRegions([]);
    showToast(t("serviceRestrictions.added", { region }));
  }

  function handleRemoveRegion(region: string) {
    const newRegions = selectedRegions.filter(r => r !== region);
    const newValue = newRegions.join(",");
    setRestrictedRegions(newValue);
    localStorage.setItem(storageKey("orderlyRestrictedRegions"), newValue);
    showToast(t("serviceRestrictions.removed", { region }));
  }

  return (
    <PageShell pageTitle="Service Restrictions">
      <div className="space-y-5">
        <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
          <div className="mb-5 flex items-center gap-2">
            <div className="flex h-8 w-8 items-center justify-center rounded-md bg-[rgba(255,99,144,0.12)] text-[#FF6390]">
              <Globe className="h-4 w-4" />
            </div>
          </div>

          <div className="mb-2">
            <label className="mb-1.5 block text-sm text-(--fg-secondary)">
              Restricted regions
            </label>
            <p className="mb-3 text-xs text-(--fg-secondary)">
              Select regions where your DEX services should be restricted.
            </p>

            <div className="relative">
              <input
                type="text"
                value={regionSearchQuery}
                onChange={e => handleRegionSearch(e.target.value)}
                placeholder="Search for a region..."
                className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
              />
            </div>

            {filteredRegions.length > 0 && (
              <div className="mt-2 max-h-48 overflow-y-auto overflow-hidden rounded-lg border border-(--line-subtle)">
                {filteredRegions.map(region => (
                  <div
                    key={region}
                    className="cursor-pointer border-b border-(--line-subtle) bg-(--bg-surface-secondary) p-2.5 text-sm text-(--fg-primary) transition-colors hover:bg-(--bg-hover) last:border-b-0"
                    onClick={() => handleSelectRegion(region)}
                  >
                    {region}
                  </div>
                ))}
              </div>
            )}

            {selectedRegions.length > 0 && (
              <div className="mt-4 flex flex-wrap gap-2">
                {selectedRegions.map(region => (
                  <div
                    key={region}
                    className="flex items-center gap-1.5 rounded-full bg-[rgba(255,99,144,0.12)] px-3 py-1.5 text-xs text-[#FF6390]"
                  >
                    <span>{region}</span>
                    <button
                      type="button"
                      onClick={() => handleRemoveRegion(region)}
                      className="transition-colors hover:text-[#FF8D89]"
                    >
                      <XCircle className="h-3.5 w-3.5" />
                    </button>
                  </div>
                ))}
              </div>
            )}

            {selectedRegions.length === 0 && (
              <p className="mt-3 text-xs text-(--fg-secondary)">
                No regions restricted. Search and select regions above.
              </p>
            )}
          </div>
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
